1728	int8_t* nn_mat_mult_kernel_s8_offset_unroll4(const int8_t *input_a,
1729	            const int8_t *input_b,
1730	            const int32_t out_tensor_ch,
1731	            const int32_t *out_shift,
1732	            const int32_t *out_scale,
1733	            const int32_t in_offset,    //value is in the range of [-127, 128]
1734	            const int32_t out_offset,   //value is in the range of [-128, 127]
1735	            const int32_t act_min,
1736	            const int32_t act_max,
1737	            const int32_t num_col_a,
1738	            const int32_t *contri_buf,
1739	            int8_t *out)
1740	{
1741	#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
1742	    // 4x4 tiled vd4dots GEMM: 4 output channels x 4 pixels per tile, LMUL=M1
1743	    // Doubles pixel throughput compared to v4 (4x2 tile, LMUL=M2)
1744	    (void)in_offset;
1745	
1746	    /* set up the four output pointers */
1747	    int8_t *out_0 = out;
1748	    int8_t *out_1 = out_0 + out_tensor_ch;
1749	    int8_t *out_2 = out_1 + out_tensor_ch;
1750	    int8_t *out_3 = out_2 + out_tensor_ch;
1751	    const int8_t *ptr_a0 = input_a;
1752	    long vl;
1753	
1754	    long maxvl_per_loop;
1755	    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1756	
1757	    // Register allocation (LMUL=M1, 32 registers):
1758	    // Accumulators: v0-v15 (16 x M1: 4 channels x 4 pixels)
1759	    //   v0=ch0*pix0  v1=ch0*pix1  v2=ch0*pix2  v3=ch0*pix3
1760	    //   v4=ch1*pix0  v5=ch1*pix1  v6=ch1*pix2  v7=ch1*pix3
1761	    //   v8=ch2*pix0  v9=ch2*pix1  v10=ch2*pix2 v11=ch2*pix3
1762	    //   v12=ch3*pix0 v13=ch3*pix1 v14=ch3*pix2 v15=ch3*pix3
1763	    // Weight loads: v16-v19 (4 x M1)
1764	    // Pixel loads: v20-v23 (4 x M1)
1765	    // Scratch for reduction: v24-v31
1766	
1767	    for (long cur_row = 0; (cur_row + 4) <= out_tensor_ch; cur_row += 4)
1768	    {
1769	        /* setup pointers for B (im2col columns / pixels) */
1770	        const int8_t *ptr_b0 = input_b;
1771	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1772	        const int8_t *ptr_b2 = ptr_b1 + num_col_a;
1773	        const int8_t *ptr_b3 = ptr_b2 + num_col_a;
1774	
1775	        /* setup pointers for A (weight rows / channels) */
1776	        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1777	        const int8_t *ptr_a2 = ptr_a1 + num_col_a;
1778	        const int8_t *ptr_a3 = ptr_a2 + num_col_a;
1779	
1780	        //init the 16 accumulators
1781	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1782	        NDS_VEC_VAND_VI(NDS_VEC_V0,  NDS_VEC_V0,  0x0);
1783	        NDS_VEC_VAND_VI(NDS_VEC_V1,  NDS_VEC_V1,  0x0);
1784	        NDS_VEC_VAND_VI(NDS_VEC_V2,  NDS_VEC_V2,  0x0);
1785	        NDS_VEC_VAND_VI(NDS_VEC_V3,  NDS_VEC_V3,  0x0);
1786	        NDS_VEC_VAND_VI(NDS_VEC_V4,  NDS_VEC_V4,  0x0);
1787	        NDS_VEC_VAND_VI(NDS_VEC_V5,  NDS_VEC_V5,  0x0);
1788	        NDS_VEC_VAND_VI(NDS_VEC_V6,  NDS_VEC_V6,  0x0);
1789	        NDS_VEC_VAND_VI(NDS_VEC_V7,  NDS_VEC_V7,  0x0);
1790	        NDS_VEC_VAND_VI(NDS_VEC_V8,  NDS_VEC_V8,  0x0);
1791	        NDS_VEC_VAND_VI(NDS_VEC_V9,  NDS_VEC_V9,  0x0);
1792	        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
1793	        NDS_VEC_VAND_VI(NDS_VEC_V11, NDS_VEC_V11, 0x0);
1794	        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
1795	        NDS_VEC_VAND_VI(NDS_VEC_V13, NDS_VEC_V13, 0x0);
1796	        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
1797	        NDS_VEC_VAND_VI(NDS_VEC_V15, NDS_VEC_V15, 0x0);
1798	
1799	        long col_count = num_col_a;
1800	
1801	        // SW-pipeline double-buffer: prologue loads first block into v16-v23,
1802	        // then the unrolled loop overlaps VLSU (v24-v31 or v16-v23) with VMAC (v16-v23 or v24-v31).
1803	        if (col_count >= maxvl_per_loop)
1804	        {
1805	            // Prologue: load first full iteration into v16-v23
1806	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1807	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1808	            NDS_VEC_VLE8_V(NDS_VEC_V17, ptr_a1);
1809	            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_a2);
1810	            NDS_VEC_VLE8_V(NDS_VEC_V19, ptr_a3);
1811	            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_b0);
1812	            NDS_VEC_VLE8_V(NDS_VEC_V21, ptr_b1);
1813	            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_b2);
1814	            NDS_VEC_VLE8_V(NDS_VEC_V23, ptr_b3);
1815	            ptr_a0 += vl; ptr_a1 += vl; ptr_a2 += vl; ptr_a3 += vl;
1816	            ptr_b0 += vl; ptr_b1 += vl; ptr_b2 += vl; ptr_b3 += vl;
1817	            col_count -= vl;
1818	
1819	            // Pipelined loop: unroll by 2.
1820	            // Iter A: load next into v24-v31, compute current (v16-v23).
1821	            // Iter B: load next into v16-v23, compute current (v24-v31).
1822	            while (col_count >= (2 * maxvl_per_loop))
1823	            {
1824	                // --- Iter A: load into v24-v31, compute v16-v23 ---
1825	                NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1826	                NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a0);
1827	                NDS_VEC_VLE8_V(NDS_VEC_V25, ptr_a1);
1828	                NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a2);
1829	                NDS_VEC_VLE8_V(NDS_VEC_V27, ptr_a3);
1830	                NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b0);
1831	                NDS_VEC_VLE8_V(NDS_VEC_V29, ptr_b1);
1832	                NDS_VEC_VLE8_V(NDS_VEC_V30, ptr_b2);
1833	                NDS_VEC_VLE8_V(NDS_VEC_V31, ptr_b3);
1834	                ptr_a0 += vl; ptr_a1 += vl; ptr_a2 += vl; ptr_a3 += vl;
1835	                ptr_b0 += vl; ptr_b1 += vl; ptr_b2 += vl; ptr_b3 += vl;
1836	                col_count -= vl;
1837	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1838	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
1839	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
1840	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
1841	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
1842	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
1843	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
1844	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
1845	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
1846	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
1847	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
1848	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
1849	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
1850	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
1851	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
1852	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
1853	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
1854	
1855	                // --- Iter B: load into v16-v23, compute v24-v31 ---
1856	                NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1857	                NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1858	                NDS_VEC_VLE8_V(NDS_VEC_V17, ptr_a1);
1859	                NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_a2);
1860	                NDS_VEC_VLE8_V(NDS_VEC_V19, ptr_a3);
1861	                NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_b0);
1862	                NDS_VEC_VLE8_V(NDS_VEC_V21, ptr_b1);
1863	                NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_b2);
1864	                NDS_VEC_VLE8_V(NDS_VEC_V23, ptr_b3);
1865	                ptr_a0 += vl; ptr_a1 += vl; ptr_a2 += vl; ptr_a3 += vl;
1866	                ptr_b0 += vl; ptr_b1 += vl; ptr_b2 += vl; ptr_b3 += vl;
1867	                col_count -= vl;
1868	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1869	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V28);
1870	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V24, NDS_VEC_V29);
1871	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V24, NDS_VEC_V30);
1872	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V24, NDS_VEC_V31);
1873	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V25, NDS_VEC_V28);
1874	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V25, NDS_VEC_V29);
1875	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V25, NDS_VEC_V30);
1876	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V25, NDS_VEC_V31);
1877	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V26, NDS_VEC_V28);
1878	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V26, NDS_VEC_V29);
1879	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V26, NDS_VEC_V30);
1880	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V26, NDS_VEC_V31);
1881	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V27, NDS_VEC_V28);
1882	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V27, NDS_VEC_V29);
1883	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V27, NDS_VEC_V30);
1884	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V27, NDS_VEC_V31);
1885	            }
1886	
1887	            // Drain: v16-v23 holds the last loaded block from prologue or iter B.
1888	            // Handle 0 or 1 remaining full iterations.
1889	            if (col_count >= maxvl_per_loop)
1890	            {
1891	                // One more full block to load into v24-v31, then compute both.
1892	                NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1893	                NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a0);
1894	                NDS_VEC_VLE8_V(NDS_VEC_V25, ptr_a1);
1895	                NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a2);
1896	                NDS_VEC_VLE8_V(NDS_VEC_V27, ptr_a3);
1897	                NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b0);
1898	                NDS_VEC_VLE8_V(NDS_VEC_V29, ptr_b1);
1899	                NDS_VEC_VLE8_V(NDS_VEC_V30, ptr_b2);
1900	                NDS_VEC_VLE8_V(NDS_VEC_V31, ptr_b3);
1901	                ptr_a0 += vl; ptr_a1 += vl; ptr_a2 += vl; ptr_a3 += vl;
1902	                ptr_b0 += vl; ptr_b1 += vl; ptr_b2 += vl; ptr_b3 += vl;
1903	                col_count -= vl;
1904	                // Compute v16-v23
1905	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1906	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
1907	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
1908	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
1909	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
1910	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
1911	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
1912	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
1913	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
1914	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
1915	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
1916	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
1917	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
1918	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
1919	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
1920	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
1921	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
1922	                // Compute v24-v31 (last full-VL block)
1923	                NDS_VEC_VSETVLI(vl, maxvl_per_loop, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1924	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V28);
1925	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V24, NDS_VEC_V29);
1926	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V24, NDS_VEC_V30);
1927	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V24, NDS_VEC_V31);
1928	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V25, NDS_VEC_V28);
1929	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V25, NDS_VEC_V29);
1930	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V25, NDS_VEC_V30);
1931	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V25, NDS_VEC_V31);
1932	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V26, NDS_VEC_V28);
1933	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V26, NDS_VEC_V29);
1934	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V26, NDS_VEC_V30);
1935	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V26, NDS_VEC_V31);
1936	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V27, NDS_VEC_V28);
1937	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V27, NDS_VEC_V29);
1938	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V27, NDS_VEC_V30);
1939	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V27, NDS_VEC_V31);
1940	            }
1941	            else
1942	            {
1943	                // No further full blocks; v16-v23 is the only remaining full-VL data.
1944	                NDS_VEC_VSETVLI(vl, maxvl_per_loop, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1945	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
1946	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
1947	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
1948	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
1949	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
1950	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
1951	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
1952	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
1953	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
1954	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
1955	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
1956	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
1957	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
1958	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
1959	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
1960	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
1961	            }
1962	        } // end if (col_count >= maxvl_per_loop)
1963	
1964	        //extra process for the case of elements to be dot producted is not a multiple of 4
1965	        if(col_count > 0)
1966	        {
1967	            //clean pixel buffers to avoid junk in tail affecting vd4dots
1968	            long tmp_avl;
